"use client"

import { useEffect, useState } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { useStore } from "@/store"
import { Button } from "@/components/ui/button"
import { 
  Building2, FolderKanban, Bell, LogOut, Plus, ChevronDown, 
  Users, Settings, BarChart3 
} from "lucide-react"

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter()
  const { 
    user, isAuthenticated, loadUser, logout,
    organizations, currentOrg, loadOrganizations, setCurrentOrg,
    projects, loadProjects, notifications, unreadCount, loadNotifications
  } = useStore()
  const [showOrgDropdown, setShowOrgDropdown] = useState(false)
  const [showNotifications, setShowNotifications] = useState(false)

  useEffect(() => {
    loadUser()
  }, [loadUser])

  useEffect(() => {
    if (!isAuthenticated) {
      router.push("/login")
    } else {
      loadOrganizations()
      loadNotifications()
    }
  }, [isAuthenticated, router, loadOrganizations, loadNotifications])

  useEffect(() => {
    if (currentOrg) {
      loadProjects(currentOrg._id)
    }
  }, [currentOrg, loadProjects])

  useEffect(() => {
    if (organizations.length > 0 && !currentOrg) {
      setCurrentOrg(organizations[0])
    }
  }, [organizations, currentOrg, setCurrentOrg])

  const handleLogout = () => {
    logout()
    router.push("/")
  }

  if (!isAuthenticated) return null

  return (
    <div className="min-h-screen flex bg-gray-50">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm">
        <div className="p-4 border-b border-gray-200">
          <Link href="/dashboard" className="text-xl font-bold text-blue-600">
            AI PM
          </Link>
        </div>

        {/* Organization Selector */}
        <div className="p-4 border-b border-gray-200">
          <div className="relative">
            <button
              onClick={() => setShowOrgDropdown(!showOrgDropdown)}
              className="w-full flex items-center justify-between p-2 rounded-lg hover:bg-gray-100 transition-colors"
            >
              <div className="flex items-center gap-2">
                <Building2 className="h-4 w-4 text-gray-600" />
                <span className="text-sm font-medium text-gray-900 truncate">
                  {currentOrg?.name || "Select Organization"}
                </span>
              </div>
              <ChevronDown className="h-4 w-4 text-gray-500" />
            </button>
            {showOrgDropdown && (
              <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-10">
                {organizations.map((org) => (
                  <button
                    key={org._id}
                    onClick={() => {
                      setCurrentOrg(org)
                      setShowOrgDropdown(false)
                    }}
                    className="w-full text-left px-3 py-2 text-sm text-gray-700 hover:bg-gray-100 first:rounded-t-lg"
                  >
                    {org.name}
                  </button>
                ))}
                <Link
                  href="/dashboard/organizations/new"
                  className="flex items-center gap-2 px-3 py-2 text-sm text-blue-600 hover:bg-blue-50 border-t border-gray-200 last:rounded-b-lg"
                  onClick={() => setShowOrgDropdown(false)}
                >
                  <Plus className="h-4 w-4" /> New Organization
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-1">
          <Link
            href="/dashboard"
            className="flex items-center gap-2 px-3 py-2 text-sm text-gray-700 rounded-lg hover:bg-gray-100 transition-colors"
          >
            <BarChart3 className="h-4 w-4 text-gray-500" /> 
            <span className="text-gray-900">Dashboard</span>
          </Link>
          
          {currentOrg && (
            <>
              <Link
                href={`/dashboard/organizations/${currentOrg._id}/members`}
                className="flex items-center gap-2 px-3 py-2 text-sm text-gray-700 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <Users className="h-4 w-4 text-gray-500" /> 
                <span className="text-gray-900">Members</span>
              </Link>
              <Link
                href={`/dashboard/organizations/${currentOrg._id}/settings`}
                className="flex items-center gap-2 px-3 py-2 text-sm text-gray-700 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <Settings className="h-4 w-4 text-gray-500" /> 
                <span className="text-gray-900">Settings</span>
              </Link>
            </>
          )}

          <div className="pt-4">
            <div className="flex items-center justify-between px-3 py-2">
              <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Projects</span>
              <Link href="/dashboard/projects/new">
                <Plus className="h-4 w-4 text-gray-400 hover:text-gray-600 transition-colors" />
              </Link>
            </div>
            {projects.map((project) => (
              <Link
                key={project._id}
                href={`/dashboard/projects/${project._id}`}
                className="flex items-center gap-2 px-3 py-2 text-sm rounded-lg hover:bg-gray-100 transition-colors"
              >
                <FolderKanban className="h-4 w-4 text-gray-500" />
                <span className="truncate text-gray-900">{project.name}</span>
              </Link>
            ))}
            {projects.length === 0 && (
              <p className="px-3 py-2 text-xs text-gray-400">No projects yet</p>
            )}
          </div>
        </nav>

        {/* User */}
        <div className="p-4 border-t border-gray-200">
          <div className="flex items-center gap-2">
            <div className="w-9 h-9 rounded-full bg-blue-600 text-white flex items-center justify-center text-sm font-medium">
              {user?.name?.charAt(0).toUpperCase()}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-gray-900 truncate">{user?.name}</p>
              <p className="text-xs text-gray-500 truncate">{user?.email}</p>
            </div>
            <Button variant="ghost" size="icon" onClick={handleLogout} className="text-gray-500 hover:text-gray-700">
              <LogOut className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <header className="h-14 border-b border-gray-200 bg-white flex items-center justify-end px-4 gap-2 shadow-sm">
          <div className="relative">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setShowNotifications(!showNotifications)}
              className="text-gray-600 hover:text-gray-900"
            >
              <Bell className="h-5 w-5" />
              {unreadCount > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center font-medium">
                  {unreadCount}
                </span>
              )}
            </Button>
            {showNotifications && (
              <div className="absolute top-full right-0 mt-2 w-80 bg-white border border-gray-200 rounded-lg shadow-lg z-10">
                <div className="p-3 border-b border-gray-200 font-medium text-gray-900">Notifications</div>
                <div className="max-h-96 overflow-y-auto">
                  {notifications.length === 0 ? (
                    <p className="p-4 text-sm text-gray-500 text-center">No notifications</p>
                  ) : (
                    notifications.slice(0, 10).map((n) => (
                      <div
                        key={n._id}
                        className={`p-3 border-b border-gray-100 text-sm ${!n.is_read ? "bg-blue-50" : ""}`}
                      >
                        <p className="font-medium text-gray-900">{n.title}</p>
                        <p className="text-gray-600">{n.message}</p>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 overflow-auto p-6 bg-gray-50">
          {children}
        </main>
      </div>
    </div>
  )
}
